def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity = 1.0
        interaction = 0.0
        dampener = 1.0
        oscillation = 0.0
        for a in range(1, 14):
            factor = 1.0
            if a % 2 == 0:
                factor *= 1.07 + 0.015 * a
                complexity *= factor
            elif a % 4 == 1:
                factor *= 0.93 - 0.012 * a
                complexity *= factor
            threshold = 0.08 * a
            if ratio < threshold:
                base_score += (a ** 3) / (2 + np.exp(ratio * a * 1.2)) * complexity
            else:
                base_score += (np.log1p(a*a*a) + ratio ** 4) * complexity / (a + 3)
            if (cap * a + item) % 11 == 0:
                base_score *= 1.06
            elif ((cap + item) * a) % 13 == 0:
                base_score *= 0.94
            if a == 7:
                for b in range(1, 8):
                    diff = cap - item * (b ** 3)
                    if diff > 0:
                        if diff % (b + 3) == 0:
                            interaction += np.cbrt(diff) / (b + 5)
                        else:
                            interaction -= np.log1p(abs(diff)) / (b + 4)
                    else:
                        interaction -= abs(diff) ** 1.5 / (b + 6)
            if ratio > 0.9 and a % 3 == 0:
                dampener *= 1.12 + 0.025 * a
            elif ratio < 0.15 and a % 5 == 0:
                dampener *= 0.85 - 0.015 * a
            if a % 6 == 2 and cap % (a + 2) == 0:
                oscillation += np.cos(a * ratio * 1.5) * 0.6
            if a == 10:
                for c in range(1, 4):
                    modulation = np.sin(c * ratio * np.pi) / (c + 1)
                    dampener += modulation * (cap % (c + 7)) * 0.01
        base_score += interaction * 0.9 + oscillation * 0.5
        base_score *= dampener
        if base_score < 0:
            priorities[i] = -base_score * (np.log1p(cap + item * 1.1) + np.sqrt(cap) * 1.2)
        else:
            if cap > item * 3.5:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + ratio * 1.1)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio ** 2.5)
        if ratio > 0.97:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.04
        if priorities[i] < -50:
            for z in range(1, 5):
                if (cap + z*z*z) % 5 == 0:
                    priorities[i] *= 1.03
                elif (cap * z) % 8 == 0:
                    priorities[i] *= 0.97
    return priorities
